import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { LoadingSpinner } from '../../components/LoadingSpinner';
import { Users, Search, Filter, Mail, Phone, Building, MapPin } from 'lucide-react';

const AlumniDirectory = () => {
  const { api, user } = useAuth();
  const [alumni, setAlumni] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [filter, setFilter] = useState('all');

  useEffect(() => {
    fetchAlumni();
  }, []);

  const fetchAlumni = async () => {
    try {
      const response = await api.get('/users?role=alumni&limit=20');
      setAlumni(response.data.users);
    } catch (error) {
      console.error('Failed to fetch alumni:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <LoadingSpinner size="large" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="page-header">
        <h1 className="page-title">Alumni Directory</h1>
        <p className="page-description">Connect with our alumni network</p>
      </div>

      {/* Search and Filter */}
      <div className="card">
        <div className="flex flex-col sm:flex-row gap-4">
          <div className="flex-1">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-5 h-5" />
              <input
                type="text"
                placeholder="Search alumni by name, company, or skills..."
                className="input pl-10"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          </div>
          <select
            className="input"
            value={filter}
            onChange={(e) => setFilter(e.target.value)}
          >
            <option value="all">All Alumni</option>
            <option value="recent">Recently Added</option>
            <option value="active">Most Active</option>
          </select>
        </div>
      </div>

      {/* Alumni Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {alumni.map((alumniUser) => (
          <div key={alumniUser._id} className="card hover:shadow-lg transition-shadow">
            <div className="flex items-start space-x-4">
              <div className="w-16 h-16 bg-primary-100 rounded-full flex items-center justify-center">
                <span className="text-primary-600 font-bold text-lg">
                  {alumniUser.name.charAt(0).toUpperCase()}
                </span>
              </div>
              <div className="flex-1 min-w-0">
                <h3 className="text-lg font-medium text-gray-900 truncate">
                  {alumniUser.name}
                </h3>
                <p className="text-sm text-gray-600">
                  {alumniUser.profile.currentCompany}
                </p>
                <p className="text-sm text-gray-500">
                  {alumniUser.profile.jobTitle}
                </p>
                <div className="mt-2 space-y-1">
                  {alumniUser.profile.branch && (
                    <p className="text-xs text-gray-500">
                      <Building className="w-3 h-3 inline mr-1" />
                      {alumniUser.profile.branch}
                    </p>
                  )}
                  {alumniUser.profile.location && (
                    <p className="text-xs text-gray-500">
                      <MapPin className="w-3 h-3 inline mr-1" />
                      {alumniUser.profile.location}
                    </p>
                  )}
                  {alumniUser.profile.graduationYear && (
                    <p className="text-xs text-gray-500">
                      Batch of {alumniUser.profile.graduationYear}
                    </p>
                  )}
                </div>
                <div className="mt-3 flex space-x-2">
                  <button className="btn btn-primary btn-sm">
                    <Mail className="w-3 h-3 mr-1" />
                    Message
                  </button>
                  <button className="btn btn-secondary btn-sm">
                    View Profile
                  </button>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {alumni.length === 0 && (
        <div className="text-center py-12">
          <Users className="w-12 h-12 text-gray-400 mx-auto mb-4" />
          <h3 className="text-lg font-medium text-gray-900 mb-2">No alumni found</h3>
          <p className="text-gray-500">Try adjusting your search or filters</p>
        </div>
      )}
    </div>
  );
};

export default AlumniDirectory;
